(function(){"use strict";gsap.to(".page-hero .hero-content",{y:-80,opacity:0,ease:"none",scrollTrigger:{trigger:".page-hero",start:"top top",end:"bottom top",scrub:!0}}),gsap.from(".service-info",{opacity:0,y:30,duration:.7,ease:"power3.out",scrollTrigger:{trigger:".service-content",start:"top 85%",toggleActions:"play none none none"}}),document.querySelectorAll(".service-step").forEach(function(e){gsap.from(e,{opacity:0,x:20,duration:.5,delay:.05,ease:"power3.out",scrollTrigger:{trigger:e,start:"top 92%",toggleActions:"play none none none"}})}),gsap.from(".service-tag",{opacity:0,scale:.9,duration:.3,stagger:.04,ease:"power3.out",scrollTrigger:{trigger:".service-tags",start:"top 95%",toggleActions:"play none none none"}}),gsap.from(".gallery-item",{opacity:0,y:40,scale:.95,duration:.6,stagger:.08,ease:"power3.out",scrollTrigger:{trigger:".gallery-grid",start:"top 85%",toggleActions:"play none none none"}}),gsap.from(".cta-card",{scale:.9,opacity:0,duration:.8,ease:"power3.out",scrollTrigger:{trigger:".cta",start:"top 80%",toggleActions:"play none none none"}}),gsap.utils.toArray(".section-title .word").forEach(function(e,t){gsap.from(e,{y:"100%",opacity:0,duration:.7,delay:t*.1,ease:"power4.out",scrollTrigger:{trigger:e.closest(".section-header"),start:"top 85%",toggleActions:"play none none none"}})}),document.querySelectorAll("[data-service]").forEach(function(e){e.addEventListener("click",function(){var n,t=document.getElementById("formService");if(t)for(n=0;n<t.options.length;n++)if(t.options[n].value===e.dataset.service||t.options[n].textContent===e.dataset.service){t.value=t.options[n].value;break}})})})()